args.sparql:
SELECT ?city ?population WHERE {
  ?station wdt:P31 wd:Q483442;
          wdt:P243 99.9;
          wdt:P2277 wd:Q912831.
  ?station wdt:P131 ?city.
  ?city wdt:P31 wd:Q515.
  ?city wdt:P1082 ?population.
  ?city wdt:P571 ?year.
  FILTER (year(?year) = 2010)
}

SELECT ?city ?population WHERE {
  ?station wdt:P31 wd:Q483442;
           wdt:P1537 99.9;
           wdt:P361 wd:Q1257.
  ?station wdt:P131 ?city.
  ?city wdt:P31 wd:Q515;
        wdt:P131 wd:Q30;
        wdt:P1082 ?population;
        wdt:P571 ?year.
  FILTER (YEAR(?year) = 2010)
}

SELECT DISTINCT ?city ?population WHERE {
  ?station wdt:P31 wd:Q483442;
           wdt:P361 wd:Q753060;
           rdfs:label ?label.
  FILTER (LANGMATCHES(LANG(?label), 'en') && CONTAINS(LCASE(?label), '99x'))
  ?station wdt:P131 ?city.
  ?city wdt:P17 wd:Q30;
        wdt:P31 wd:Q515.
  ?city wdt:P1082 ?population.
  ?population wdt:P585 ?time.
  FILTER (YEAR(?time) = 2010)
}

SELECT ?city ?population WHERE {
  ?station wdt:P31 wd:Q483442 ;
           rdfs:label ?label.
  FILTER (LANG(?label) = 'en' && CONTAINS(LCASE(?label), '99x'))
  ?station wdt:P131 ?city.
  ?city wdt:P17 wd:Q30 ;
        wdt:P31 wd:Q515.
  ?city wdt:P1082 ?population.
  ?population p:P1082 ?popStmnt.
  ?popStmnt pq:P585 ?time.
  FILTER (YEAR(?time) = 2010)
}

SELECT DISTINCT ?city ?populationValue WHERE {
  ?station wdt:P31 wd:Q483442 ;
          wdt:P1553 ?branding ;
          wdt:P131 ?city .
  ?city wdt:P17 wd:Q30 ;
        wdt:P31 wd:Q515 .
  ?city wdt:P1082 ?populationStatement .
  ?populationStatement ps:P1082 ?populationValue ;
                   pq:P585 ?time .
  FILTER (CONTAINS(LCASE(?branding), '99x'))
  FILTER (YEAR(?time) = 2010)
}

SELECT DISTINCT ?city ?populationValue WHERE {
  ?station wdt:P31 wd:Q483442;
          rdfs:label ?label.
  FILTER (LANG(?label) = 'en' && CONTAINS(LCASE(?label), '99x'))
  ?station wdt:P131 ?city.
  ?city wdt:P131+ wd:Q1257;
        wdt:P17 wd:Q30;
        wdt:P31 wd:Q515.
  ?city wdt:P1082 ?populationStatement.
  ?populationStatement ps:P1082 ?populationValue;
                   pq:P585 ?time.
  FILTER (YEAR(?time) = 2010)
}

SELECT ?populationValue WHERE {
  wd:Q3855 wdt:P1082 ?populationStatement.
  ?populationStatement ps:P1082 ?populationValue;
                     pq:P585 ?time.
  FILTER (YEAR(?time) = 2010)
}
